-#[test]
-fn ratio_is_weighted_against_other_grow_items() {
-    let area = Rect::new(0, 0, 100, 10);
-
-    // Ratio weights are computed as (n/d). Fill has weight 1.0.
-    // So Ratio(1,4) vs Fill is 0.25 vs 1.0 => 20% vs 80%.
